const root = $input.first().json;
const cfg = { 
  crm_base_url: root.crm_base_url, 
  booking_offers_url: root.booking_offers_url 
};

// Payload is nested under root.body when coming from webhook
const body = root.body || root;
const event = body.event;
const workspaceOwnerId = body.workspace_owner_id;
const emittedAt = body.emitted_at;
const payload = body.payload || {};
const document = payload.document || {};
const invoice = payload.invoice || {};
const contact = payload.contact || document.contact || invoice.contact || {};

const contactId = 
  payload.contact_id || 
  contact.id || 
  document.contact_id || 
  invoice.contact_id || 
  null;

const documentId = 
  payload.document_id || 
  document.id || 
  invoice.quote_id || 
  payload.invoice_id || 
  payload.quote_id || 
  null;

const idempotencyKey = documentId 
  ? `${contactId}:${documentId}` 
  : `${contactId}:no-quote`;

const crmBase = (cfg.crm_base_url || 'https://www.clickin360.com').replace(/\/$/, '');

const onboardingToken = payload.onboarding_token || contact.onboarding_token || null;
const onboardingUrl = onboardingToken 
  ? `${crmBase}/onboarding/${onboardingToken}` 
  : null;

const locale = contact.preferred_language === 'en' ? 'en' : 'es';
const firstName = contact.first_name || 'there';
const contactEmail = contact.email || null;

let action = 'stop';
let reason = '';

if (event === 'onboarding.manual_start') {
  action = 'start';

} else if (event === 'invoice.paid') {
  if (invoice.invoice_type === 'quote' || invoice.quote_id) {
    action = 'start';
  } else {
    reason = 'invoice is not quote-type';
  }

} else if (event === 'quote.accepted') {
  action = 'record_quote';

} else {
  reason = `unhandled event: ${event}`;
}

return [{ 
  json: { 
    event, 
    action,
    reason,
    payload, 
    document, 
    invoice, 
    contact, 
    contactId, 
    documentId, 
    workspaceOwnerId, 
    idempotencyKey, 
    onboardingUrl, 
    locale, 
    contactEmail,
    firstName,
    emitted_at: emittedAt,
    ...cfg 
  } 
}];

const d = $input.first().json;
let action = 'stop';
let reason = '';
if (d.event === 'onboarding.manual_start') { action = 'start'; reason = 'manual_override'; }
else if (d.event === 'quote.accepted') { action = 'record_quote'; reason = 'quote_accepted_pending_invoice'; }
else if (d.event === 'invoice.paid') {
  const quoteId = d.invoice?.quote_id || d.documentId;
  action = 'start';
  reason = quoteId ? 'invoice_paid_with_quote' : 'invoice_paid_no_quote';
}
return [{ json: { ...d, action, reason } }];

const d = $('Gate: Should Start Onboarding?').first().json;
const booking = d.booking_offers_url || (d.crm_base_url + '/api/leads/booking-offers?lang=es');
const isEn = d.locale === 'en';
const subject = isEn ? 'Welcome to ClickIn 360 — next steps' : 'Bienvenido a ClickIn 360 — siguientes pasos';
const text = isEn
  ? `Hi ${d.firstName},

Welcome to ClickIn 360! Your onboarding has started.

1) Complete the questionnaire: ${d.onboardingUrl || '(link will be sent separately)'}
2) Book your kickoff call: ${booking}

Thank you!`
  : `Hola ${d.firstName},

¡Bienvenido a ClickIn 360! Tu incorporación ha comenzado.

1) Completa el cuestionario: ${d.onboardingUrl || '(enlace por separado)'}
2) Agenda tu llamada de inicio: ${booking}

¡Gracias!`;
return [{ json: { ...d, subject, text, toEmail: d.contactEmail } }];

